import { useState, useRef, useEffect } from "react";
import API from "../services/api";
import { useTheme } from "../context/ThemeContext";
import PrivacyPicker from "./PrivacyPicker";
import "./ProfileModal.css";

export default function ProfileModal({ currentUser, onClose, onProfileUpdate, onLogout }) {
  const [tab, setTab] = useState("profile");
  const [bio, setBio] = useState(currentUser?.bio || "");
  const [profilePic, setProfilePic] = useState(currentUser?.profilePic || "");
  const [isPrivate, setIsPrivate] = useState(currentUser?.isPrivate || false);
  const [settings, setSettings] = useState(currentUser?.settings || {
    showReadReceipts: true,
    profilePicPrivacy: "everyone",
    lastSeenPrivacy: "everyone",
    onlinePrivacy: "everyone",
    profilePicCloseFriends: [],
    lastSeenCloseFriends: [],
    onlineCloseFriends: [],
  });
  const [notifSettings, setNotifSettings] = useState(currentUser?.notificationSettings || {
    sound: true, pushEnabled: true, dndEnabled: false, dndStart: "22:00", dndEnd: "08:00"
  });
  const [followers, setFollowers] = useState([]);
  const [following, setFollowing] = useState([]);
  const [requests, setRequests] = useState([]);
  const [blocked, setBlocked] = useState([]);
  const [saving, setSaving] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [savingNotif, setSavingNotif] = useState(false);
  const [notifSaved, setNotifSaved] = useState(false);

  // Security
  const [currentPwd, setCurrentPwd] = useState("");
  const [newPwd, setNewPwd] = useState("");
  const [confirmPwd, setConfirmPwd] = useState("");
  const [deletePwd, setDeletePwd] = useState("");
  const [securityMsg, setSecurityMsg] = useState({ text: "", type: "" });
  const [securityTab, setSecurityTab] = useState("password");
  const [sessions, setSessions] = useState([]);

  const fileRef = useRef();
  const { theme, toggleTheme } = useTheme();

  useEffect(() => { fetchData(); }, []);

  const fetchData = async () => {
    try {
      const res = await API.get(`/users/${currentUser.username}`);
      setFollowers(res.data.followers || []);
      setFollowing(res.data.following || []);
      setRequests(res.data.followRequests || []);
      setBlocked(res.data.blockedUsers || []);
      setProfilePic(res.data.profilePic || "");
      setBio(res.data.bio || "");
      setIsPrivate(res.data.isPrivate || false);
      if (res.data.settings) setSettings(res.data.settings);
      if (res.data.notificationSettings) setNotifSettings(res.data.notificationSettings);
    } catch (err) { console.log(err); }
  };

  const fetchSessions = async () => {
    try {
      const res = await API.get("/users/me/sessions");
      setSessions(res.data);
    } catch (err) { console.log(err); }
  };

  const handlePicUpload = async (e) => {
    const file = e.target.files[0]; if (!file) return;
    setUploading(true);
    const fd = new FormData(); fd.append("profilePic", file);
    try {
      const res = await API.post("/users/me/pic", fd);
      setProfilePic(res.data.profilePic);
      onProfileUpdate && onProfileUpdate({ ...currentUser, profilePic: res.data.profilePic });
    } catch (err) { console.log(err); }
    setUploading(false);
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      await API.put("/users/me/profile", { bio, isPrivate });
      onProfileUpdate && onProfileUpdate({ ...currentUser, bio, isPrivate });
    } catch (err) { console.log(err); }
    setSaving(false);
  };

  const handleSettingToggle = async (key) => {
    const newVal = !settings[key];
    const newSettings = { ...settings, [key]: newVal };
    setSettings(newSettings);
    try {
      await API.put("/users/me/settings", { [key]: newVal });
      onProfileUpdate && onProfileUpdate({ ...currentUser, settings: newSettings });
    } catch (err) { console.log(err); }
  };

  const handlePrivacyChange = async (key, closeFriendsKey, value) => {
    const newSettings = { ...settings, [key]: value };
    setSettings(newSettings);
    try {
      await API.put("/users/me/settings", { [key]: value, [closeFriendsKey]: settings[closeFriendsKey] || [] });
      onProfileUpdate && onProfileUpdate({ ...currentUser, settings: newSettings });
    } catch (err) { console.log(err); }
  };

  const handleCloseFriendToggle = async (listKey, privacyKey, username) => {
    const current = settings[listKey] || [];
    const updated = current.includes(username) ? current.filter(u => u !== username) : [...current, username];
    const newSettings = { ...settings, [listKey]: updated };
    setSettings(newSettings);
    try {
      await API.put("/users/me/settings", { [listKey]: updated, [privacyKey]: settings[privacyKey] });
      onProfileUpdate && onProfileUpdate({ ...currentUser, settings: newSettings });
    } catch (err) { console.log(err); }
  };

  const handleSaveNotif = async () => {
    setSavingNotif(true);
    try {
      await API.put("/users/me/settings", notifSettings);
      onProfileUpdate && onProfileUpdate({ ...currentUser, notificationSettings: notifSettings });
      setNotifSaved(true); setTimeout(() => setNotifSaved(false), 2000);
    } catch (err) { console.log(err); }
    setSavingNotif(false);
  };

  const requestPushPermission = async () => {
    if (!("Notification" in window)) return;
    const perm = await Notification.requestPermission();
    if (perm === "granted") {
      setNotifSettings(prev => ({ ...prev, pushEnabled: true }));
      new Notification("ChatApp", { body: "Push notifications enabled! 🎉" });
    }
  };

  const handleChangePassword = async () => {
    if (!currentPwd || !newPwd || !confirmPwd) return setSecurityMsg({ text: "Fill all fields", type: "error" });
    if (newPwd !== confirmPwd) return setSecurityMsg({ text: "Passwords don't match", type: "error" });
    if (newPwd.length < 6) return setSecurityMsg({ text: "Min 6 characters", type: "error" });
    try {
      await API.post("/users/me/change-password", { currentPassword: currentPwd, newPassword: newPwd });
      setSecurityMsg({ text: "✅ Password changed!", type: "success" });
      setCurrentPwd(""); setNewPwd(""); setConfirmPwd("");
    } catch (err) {
      setSecurityMsg({ text: err.response?.data?.message || "Failed", type: "error" });
    }
    setTimeout(() => setSecurityMsg({ text: "", type: "" }), 3000);
  };

  const handleDeleteAccount = async () => {
    if (!deletePwd) return setSecurityMsg({ text: "Enter your password", type: "error" });
    if (!window.confirm("⚠️ Permanently delete your account? This cannot be undone.")) return;
    try {
      await API.post("/users/me/delete-account", { password: deletePwd });
      onLogout && onLogout();
    } catch (err) {
      setSecurityMsg({ text: err.response?.data?.message || "Failed", type: "error" });
    }
  };

  const handleAccept = async (username) => {
    try { await API.post(`/users/${username}/accept`); setRequests(r => r.filter(u => u.username !== username)); fetchData(); } catch {}
  };
  const handleDecline = async (username) => {
    try { await API.post(`/users/${username}/decline`); setRequests(r => r.filter(u => u.username !== username)); } catch {}
  };
  const handleUnblock = async (username) => {
    try { await API.post(`/users/${username}/unblock`); setBlocked(b => b.filter(u => (u.username || u) !== username)); } catch {}
  };

  const tabs = [
    { id: "profile",       label: "Profile" },
    { id: "requests",      label: requests.length > 0 ? `Requests (${requests.length})` : "Requests" },
    { id: "followers",     label: "Followers" },
    { id: "following",     label: "Following" },
    { id: "blocked",       label: blocked.length > 0 ? `Blocked (${blocked.length})` : "Blocked" },
    { id: "privacy",       label: "Privacy" },
    { id: "notifications", label: "🔔 Notifs" },
    { id: "security",      label: "🔐 Security" },
  ];

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="pm-modal" onClick={e => e.stopPropagation()}>
        <button className="pm-close" onClick={onClose}>✕</button>

        <div className="pm-top">
          <div className="pm-avatar-wrap" onClick={() => fileRef.current.click()}>
            {profilePic
              ? <img src={profilePic} alt="" className="pm-avatar-img" />
              : <div className="pm-avatar-letter">{currentUser?.username?.[0]?.toUpperCase()}</div>
            }
            <div className="pm-avatar-hover">{uploading ? "⏳" : "📷"}</div>
          </div>
          <input ref={fileRef} type="file" accept="image/*" hidden onChange={handlePicUpload} />
          <h2 className="pm-uname">@{currentUser?.username}</h2>
          <div className="pm-privacy-badge">{isPrivate ? "🔒 Private" : "🌐 Public"}</div>
          <div className="pm-stats">
            <div className="pm-stat" onClick={() => setTab("followers")}>
              <span className="pm-stat-n">{followers.length}</span>
              <span className="pm-stat-l">Followers</span>
            </div>
            <div className="pm-divider" />
            <div className="pm-stat" onClick={() => setTab("following")}>
              <span className="pm-stat-n">{following.length}</span>
              <span className="pm-stat-l">Following</span>
            </div>
            {requests.length > 0 && <>
              <div className="pm-divider" />
              <div className="pm-stat" onClick={() => setTab("requests")}>
                <span className="pm-stat-n" style={{color:"var(--accent)"}}>{requests.length}</span>
                <span className="pm-stat-l">Requests</span>
              </div>
            </>}
          </div>
        </div>

        <div className="pm-tabs">
          {tabs.map(t => (
            <button key={t.id} className={`pm-tab ${tab === t.id ? "active" : ""}`} onClick={() => { setTab(t.id); if(t.id === "security") fetchSessions(); }}>
              {t.label}
            </button>
          ))}
        </div>

        <div className="pm-body">

          {/* Profile */}
          {tab === "profile" && (
            <div className="pm-profile-tab">
              <label className="pm-label">BIO</label>
              <textarea className="pm-bio" placeholder="Write something about yourself..."
                value={bio} onChange={e => setBio(e.target.value)} maxLength={150} />
              <span className="pm-count">{bio.length}/150</span>
              <label className="pm-label" style={{marginTop:"16px"}}>ACCOUNT TYPE</label>
              <div className="pm-toggle-row">
                <div>
                  <div className="pm-toggle-title">{isPrivate ? "🔒 Private Account" : "🌐 Public Account"}</div>
                  <div className="pm-toggle-sub">{isPrivate ? "Only approved followers can message you" : "Anyone can follow and message you"}</div>
                </div>
                <button className={`toggle-btn ${isPrivate ? "on" : ""}`} onClick={() => setIsPrivate(!isPrivate)}>
                  <span className="toggle-thumb" />
                </button>
              </div>
              <label className="pm-label" style={{marginTop:"16px"}}>APPEARANCE</label>
              <div className="pm-toggle-row">
                <div>
                  <div className="pm-toggle-title">{theme === "dark" ? "🌙 Dark Mode" : "☀️ Light Mode"}</div>
                  <div className="pm-toggle-sub">Switch between light and dark theme</div>
                </div>
                <button className={`toggle-btn ${theme === "dark" ? "on" : ""}`} onClick={toggleTheme}>
                  <span className="toggle-thumb" />
                </button>
              </div>
              <button className="pm-save" onClick={handleSave} disabled={saving}>{saving ? "Saving..." : "Save Changes"}</button>
            </div>
          )}

          {/* Requests */}
          {tab === "requests" && (
            <div className="pm-user-list">
              {requests.length === 0 ? <p className="pm-empty">No pending requests</p>
                : requests.map(u => (
                  <div key={u._id} className="pm-request-row">
                    <div className="pm-user-av">{u.profilePic ? <img src={u.profilePic} alt="" /> : u.username?.[0]?.toUpperCase()}</div>
                    <span className="pm-user-name">@{u.username}</span>
                    <div className="pm-request-btns">
                      <button className="accept-btn" onClick={() => handleAccept(u.username)}>✓</button>
                      <button className="decline-btn" onClick={() => handleDecline(u.username)}>✕</button>
                    </div>
                  </div>
                ))
              }
            </div>
          )}

          {/* Followers */}
          {tab === "followers" && (
            <div className="pm-user-list">
              {followers.length === 0 ? <p className="pm-empty">No followers yet</p>
                : followers.map(u => (
                  <div key={u._id} className="pm-user-row">
                    <div className="pm-user-av">{u.profilePic ? <img src={u.profilePic} alt="" /> : u.username?.[0]?.toUpperCase()}</div>
                    <span className="pm-user-name">@{u.username}</span>
                  </div>
                ))
              }
            </div>
          )}

          {/* Following */}
          {tab === "following" && (
            <div className="pm-user-list">
              {following.length === 0 ? <p className="pm-empty">Not following anyone yet</p>
                : following.map(u => (
                  <div key={u._id} className="pm-user-row">
                    <div className="pm-user-av">{u.profilePic ? <img src={u.profilePic} alt="" /> : u.username?.[0]?.toUpperCase()}</div>
                    <span className="pm-user-name">@{u.username}</span>
                  </div>
                ))
              }
            </div>
          )}

          {/* Blocked */}
          {tab === "blocked" && (
            <div className="pm-user-list">
              {blocked.length === 0 ? <p className="pm-empty">You haven't blocked anyone</p>
                : blocked.map((u, i) => {
                  const username = u.username || u;
                  return (
                    <div key={u._id || i} className="pm-blocked-row">
                      <div className="pm-user-av">{u.profilePic ? <img src={u.profilePic} alt="" /> : (username?.[0] || "?").toUpperCase()}</div>
                      <span className="pm-user-name">@{username}</span>
                      <button className="pm-unblock-btn" onClick={() => handleUnblock(username)}>Unblock</button>
                    </div>
                  );
                })
              }
            </div>
          )}

          {/* Privacy */}
          {tab === "privacy" && (
            <div className="pm-settings">
              <label className="pm-label">MESSAGING</label>
              <div className="pm-toggle-row">
                <div>
                  <div className="pm-toggle-title">🔵 Blue Ticks (Read Receipts)</div>
                  <div className="pm-toggle-sub">Show when you've read messages</div>
                </div>
                <button className={`toggle-btn ${settings.showReadReceipts ? "on" : ""}`} onClick={() => handleSettingToggle("showReadReceipts")}>
                  <span className="toggle-thumb" />
                </button>
              </div>

              <label className="pm-label" style={{marginTop:"18px"}}>PROFILE PICTURE</label>
              <PrivacyPicker
                label="Who can see your profile picture?"
                value={settings.profilePicPrivacy || "everyone"}
                onChange={(val) => handlePrivacyChange("profilePicPrivacy", "profilePicCloseFriends", val)}
                showCloseFriends={true}
                closeFriends={settings.profilePicCloseFriends || []}
                onToggleCloseFriend={(u) => handleCloseFriendToggle("profilePicCloseFriends", "profilePicPrivacy", u)}
                followers={followers}
              />

              <label className="pm-label" style={{marginTop:"18px"}}>LAST SEEN</label>
              <PrivacyPicker
                label="Who can see your last seen?"
                value={settings.lastSeenPrivacy || "everyone"}
                onChange={(val) => handlePrivacyChange("lastSeenPrivacy", "lastSeenCloseFriends", val)}
                showCloseFriends={true}
                closeFriends={settings.lastSeenCloseFriends || []}
                onToggleCloseFriend={(u) => handleCloseFriendToggle("lastSeenCloseFriends", "lastSeenPrivacy", u)}
                followers={followers}
              />

              <label className="pm-label" style={{marginTop:"18px"}}>ONLINE STATUS</label>
              <PrivacyPicker
                label="Who can see when you're online?"
                value={settings.onlinePrivacy || "everyone"}
                onChange={(val) => handlePrivacyChange("onlinePrivacy", "onlineCloseFriends", val)}
                showCloseFriends={true}
                closeFriends={settings.onlineCloseFriends || []}
                onToggleCloseFriend={(u) => handleCloseFriendToggle("onlineCloseFriends", "onlinePrivacy", u)}
                followers={followers}
              />
            </div>
          )}

          {/* Notifications */}
          {tab === "notifications" && (
            <div className="pm-settings">
              <label className="pm-label">SOUNDS & ALERTS</label>
              <div className="pm-toggle-row">
                <div>
                  <div className="pm-toggle-title">🔊 Message Sound</div>
                  <div className="pm-toggle-sub">Play sound when a message arrives</div>
                </div>
                <button className={`toggle-btn ${notifSettings.sound ? "on" : ""}`}
                  onClick={() => setNotifSettings(prev => ({ ...prev, sound: !prev.sound }))}>
                  <span className="toggle-thumb" />
                </button>
              </div>

              <div className="pm-toggle-row">
                <div>
                  <div className="pm-toggle-title">📱 Push Notifications</div>
                  <div className="pm-toggle-sub">
                    {Notification.permission === "granted" ? "✅ Browser notifications enabled" : "Click to enable browser notifications"}
                  </div>
                </div>
                <button className={`toggle-btn ${notifSettings.pushEnabled && Notification.permission === "granted" ? "on" : ""}`}
                  onClick={() => Notification.permission !== "granted" ? requestPushPermission() : setNotifSettings(prev => ({ ...prev, pushEnabled: !prev.pushEnabled }))}>
                  <span className="toggle-thumb" />
                </button>
              </div>

              <label className="pm-label" style={{marginTop:"18px"}}>DO NOT DISTURB</label>
              <div className="pm-toggle-row">
                <div>
                  <div className="pm-toggle-title">🌙 Do Not Disturb</div>
                  <div className="pm-toggle-sub">Mute notifications during set hours</div>
                </div>
                <button className={`toggle-btn ${notifSettings.dndEnabled ? "on" : ""}`}
                  onClick={() => setNotifSettings(prev => ({ ...prev, dndEnabled: !prev.dndEnabled }))}>
                  <span className="toggle-thumb" />
                </button>
              </div>

              {notifSettings.dndEnabled && (
                <div className="dnd-schedule">
                  <div className="dnd-row">
                    <label className="dnd-label">From</label>
                    <input type="time" className="dnd-input" value={notifSettings.dndStart}
                      onChange={e => setNotifSettings(prev => ({ ...prev, dndStart: e.target.value }))} />
                  </div>
                  <div className="dnd-row">
                    <label className="dnd-label">To</label>
                    <input type="time" className="dnd-input" value={notifSettings.dndEnd}
                      onChange={e => setNotifSettings(prev => ({ ...prev, dndEnd: e.target.value }))} />
                  </div>
                </div>
              )}

              <button className="pm-save" style={{marginTop:"16px"}} onClick={handleSaveNotif} disabled={savingNotif}>
                {notifSaved ? "✅ Saved!" : savingNotif ? "Saving..." : "Save Notification Settings"}
              </button>
            </div>
          )}

          {/* Security */}
          {tab === "security" && (
            <div className="pm-settings">
              <div className="pm-tabs" style={{marginBottom:"12px",border:"none",padding:"0"}}>
                <button className={`pm-tab ${securityTab === "password" ? "active" : ""}`} onClick={() => setSecurityTab("password")}>Password</button>
                <button className={`pm-tab ${securityTab === "sessions" ? "active" : ""}`} onClick={() => { setSecurityTab("sessions"); fetchSessions(); }}>Sessions</button>
                <button className={`pm-tab ${securityTab === "delete" ? "active" : ""}`} onClick={() => setSecurityTab("delete")}>Delete Account</button>
              </div>

              {securityMsg.text && (
                <div className={`sec-msg ${securityMsg.type}`} style={{padding:"10px 14px",borderRadius:"10px",fontSize:"13px",marginBottom:"12px",background: securityMsg.type === "error" ? "rgba(224,85,85,0.1)" : "rgba(16,185,129,0.1)", color: securityMsg.type === "error" ? "var(--danger)" : "var(--teal)"}}>
                  {securityMsg.text}
                </div>
              )}

              {securityTab === "password" && (
                <div style={{display:"flex",flexDirection:"column",gap:"10px"}}>
                  <label className="pm-label">CURRENT PASSWORD</label>
                  <input type="password" className="pm-bio" style={{minHeight:"unset",padding:"11px 14px"}}
                    placeholder="Current password" value={currentPwd} onChange={e => setCurrentPwd(e.target.value)} />
                  <label className="pm-label">NEW PASSWORD</label>
                  <input type="password" className="pm-bio" style={{minHeight:"unset",padding:"11px 14px"}}
                    placeholder="Min 6 characters" value={newPwd} onChange={e => setNewPwd(e.target.value)} />
                  <label className="pm-label">CONFIRM NEW PASSWORD</label>
                  <input type="password" className="pm-bio" style={{minHeight:"unset",padding:"11px 14px"}}
                    placeholder="Repeat new password" value={confirmPwd} onChange={e => setConfirmPwd(e.target.value)} />
                  <button className="pm-save" onClick={handleChangePassword}>Change Password</button>
                </div>
              )}

              {securityTab === "sessions" && (
                <div style={{display:"flex",flexDirection:"column",gap:"8px"}}>
                  <p className="pm-label" style={{marginBottom:"4px"}}>ACTIVE SESSIONS</p>
                  {sessions.length === 0
                    ? <p className="pm-empty">No active sessions found</p>
                    : sessions.map(s => (
                      <div key={s.sessionId} style={{display:"flex",alignItems:"center",gap:"12px",padding:"12px 14px",background:"var(--bg3)",borderRadius:"14px",border:"1px solid var(--border2)"}}>
                        <span style={{fontSize:"24px"}}>📱</span>
                        <div style={{flex:1}}>
                          <div style={{fontSize:"13px",fontWeight:"600",color:"var(--text)"}}>{s.device || "Unknown device"}</div>
                          <div style={{fontSize:"11px",color:"var(--text3)"}}>{s.ip} · {new Date(s.lastActive).toLocaleDateString()}</div>
                        </div>
                        <button onClick={async () => { await API.delete(`/users/me/sessions/${s.sessionId}`); fetchSessions(); }}
                          style={{padding:"6px 12px",background:"rgba(224,85,85,0.1)",border:"1px solid rgba(224,85,85,0.2)",borderRadius:"8px",color:"var(--danger)",fontSize:"12px",fontWeight:"600",cursor:"pointer"}}>
                          Revoke
                        </button>
                      </div>
                    ))
                  }
                </div>
              )}

              {securityTab === "delete" && (
                <div style={{display:"flex",flexDirection:"column",gap:"12px"}}>
                  <div style={{background:"rgba(224,85,85,0.08)",border:"1px solid rgba(224,85,85,0.2)",borderRadius:"14px",padding:"20px",textAlign:"center"}}>
                    <div style={{fontSize:"36px",marginBottom:"8px"}}>⚠️</div>
                    <h3 style={{fontSize:"16px",fontWeight:"700",color:"var(--danger)",margin:"0 0 8px"}}>Delete Account</h3>
                    <p style={{fontSize:"13px",color:"var(--text2)",margin:0,lineHeight:"1.5"}}>
                      This will permanently delete your account, all messages, and data. Cannot be undone.
                    </p>
                  </div>
                  <input type="password" className="pm-bio" style={{minHeight:"unset",padding:"11px 14px"}}
                    placeholder="Enter your password to confirm" value={deletePwd} onChange={e => setDeletePwd(e.target.value)} />
                  <button onClick={handleDeleteAccount} disabled={!deletePwd}
                    style={{padding:"13px",background:"rgba(224,85,85,0.15)",border:"1.5px solid rgba(224,85,85,0.3)",borderRadius:"14px",color:"var(--danger)",fontSize:"14px",fontWeight:"700",cursor:"pointer",opacity: deletePwd ? 1 : 0.5}}>
                    🗑 Delete My Account
                  </button>
                </div>
              )}
            </div>
          )}

        </div>
      </div>
    </div>
  );
}
